function usePathname() {
  const getPath = () => {
    const raw = window.location.pathname || "/";
    const clean = raw.replace(/\/+$/, "") || "/";
    return clean === "" ? "/" : clean;
  };

  const [path, setPath] = useState(() =>
    typeof window === "undefined" ? "/" : getPath()
  );

  useEffect(() => {
    const onPop = () => setPath(getPath());
    window.addEventListener("popstate", onPop);
    return () => window.removeEventListener("popstate", onPop);
  }, []);

  const navigate = (to) => {
    const next = (to || "/").replace(/\/+$/, "") || "/";
    if (next === path) return;
    window.history.pushState({}, "", next);
    setPath(next);
    try {
      window.scrollTo({ top: 0, behavior: "auto" });
    } catch (e) {
      window.scrollTo(0, 0);
    }
  };

  return { path, navigate };
}

function StripeBuyButton({ buyButtonId, publishableKey }) {
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const existing = document.querySelector(
      'script[src="https://js.stripe.com/v3/buy-button.js"]'
    );
    if (existing) {
      setReady(true);
      return;
    }

    const script = document.createElement("script");
    script.async = true;
    script.src = "https://js.stripe.com/v3/buy-button.js";
    script.onload = () => setReady(true);
    script.onerror = () => setReady(false);
    document.body.appendChild(script);
  }, []);

  if (!buyButtonId || !publishableKey) {
    return (
      <div className="rounded-xl border border-white/10 bg-white/5 p-4 text-sm text-white/75">
        Stripe is not configured yet.
      </div>
    );
  }

  return (
    <div className="min-h-[60px]">
      {!ready ? (
        <div className="rounded-xl border border-white/10 bg-white/5 p-4 text-sm text-white/70">
          Loading secure checkout…
        </div>
      ) : (
        <stripe-buy-button
          buy-button-id={buyButtonId}
          publishable-key={publishableKey}
        ></stripe-buy-button>
      )}
    </div>
  );
}

