    const u1ms = u1 instanceof Date ? u1.getTime() : null;
    const u4ms = u4 instanceof Date ? u4.getTime() : null;
    const t1ms = t1 instanceof Date ? t1.getTime() : null;
    const t4ms = t4 instanceof Date ? t4.getTime() : null;

